% pdiskmon.m
% function phi=pdiskmon(a,h,rho,kmax)
% disk, radius a,  in plane z=0; around z-axis; field point: rho,h
% compute potential generated by mono layer; J/sigma=1;
% version: 20021228
% a. van Oosterom
% using analytical expansion in Legendre plynomials

function phi=pdiskmon(a,h,rho,kmax)
hsq=h^2;
r=sqrt(rho^2+hsq);
mu=0; if r ~= 0, mu=abs(h/r); end

if r > a,
  ar=a/r;
  arsq=ar*ar;
  phi=ar;
  facar=ar;
else,
  ra=r/a;
  rasq=ra*ra;
  phi=2*(1-ra*mu);
end

for k=1:kmax,

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% script for computing legendre polynomial of order zero and degree k
% note: used for k=1:kmax
   if k==1,
      pk=mu;
      pkmm=1;
      pkm=mu;
   else,
      pk=((2*k-1)*mu*pkm-(k-1)*pkmm)/k;   
      pkmm=pkm;
      pkm=pk;
   end

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% (rem is standard matlab remainder function)
   if rem(k,2)==0 & k>=2,
      if r > a,
         facar=-facar*arsq*(k-1)/(k+2);
         phi=phi+facar*pk;
      else,
         if k==2,facra=rasq;else
                 facra=-facra*rasq*(k-3)/k;end
         phi=phi+facra*pk;  
      end
   end
end 
phi=phi*a/4;

